        }
        else if (checkCube && collision.CompareTag("Cube")) 
        { 
            roomDatas.SetCubeCheck(); 
            snap.Snap(gameObject.transform.position);
        }
        if (checkCompile) {
            checkCompile = false;
        }
    }
}

